#!/usr/bin/env node
// Extract memory values from an ELF binary by modeling its load image.
// Base image address 0x400000; emit little-endian 32-bit words at each
// 4-byte-aligned virtual address backed by a PT_LOAD segment's file data.

const fs = require('fs');

const path = process.argv[2];
if (!path) {
  process.stderr.write('usage: node extract.js <binary>\n');
  process.exit(1);
}

const buf = fs.readFileSync(path);

// --- ELF header sanity ---
if (buf.length < 64 ||
    buf[0] !== 0x7f || buf[1] !== 0x45 || buf[2] !== 0x4c || buf[3] !== 0x46) {
  process.stderr.write('not an ELF file\n');
  process.exit(1);
}

const is64 = buf[4] === 2; // EI_CLASS: 2 = ELF64
const little = buf[5] === 1; // EI_DATA: 1 = little-endian

const rd = (off, size) => {
  let v = 0n;
  for (let i = 0; i < size; i++) {
    const byte = BigInt(buf[off + (little ? i : size - 1 - i)]);
    v |= byte << (8n * BigInt(i));
  }
  return v;
};

const IMAGE_BASE = 0x400000n;
const PT_LOAD = 1;

const mem = new Map(); // vaddr (Number) -> byte

if (!is64) {
  process.stderr.write('only ELF64 supported\n');
  process.exit(1);
}

const e_phoff = Number(rd(0x20, 8));
const e_phentsize = Number(rd(0x36, 2));
const e_phnum = Number(rd(0x38, 2));

for (let i = 0; i < e_phnum; i++) {
  const ph = e_phoff + i * e_phentsize;
  const p_type = Number(rd(ph + 0, 4));
  if (p_type !== PT_LOAD) continue;
  const p_offset = Number(rd(ph + 8, 8));
  const p_vaddr = rd(ph + 16, 8);
  const p_filesz = Number(rd(ph + 32, 8));
  for (let j = 0; j < p_filesz; j++) {
    const fileIdx = p_offset + j;
    if (fileIdx >= buf.length) break;
    const addr = IMAGE_BASE + p_vaddr + BigInt(j);
    mem.set(addr.toString(), buf[fileIdx]);
  }
}

// Emit 4-byte-aligned little-endian words fully backed by mapped bytes.
const out = {};
for (const [addrStr] of mem) {
  const addr = BigInt(addrStr);
  if (addr % 4n !== 0n) continue;
  const b0 = mem.get(addrStr);
  const b1 = mem.get((addr + 1n).toString());
  const b2 = mem.get((addr + 2n).toString());
  const b3 = mem.get((addr + 3n).toString());
  if (b0 === undefined || b1 === undefined ||
      b2 === undefined || b3 === undefined) continue;
  const val = (b0 | (b1 << 8) | (b2 << 16) | (b3 << 24)) >>> 0;
  out[addrStr] = val;
}

process.stdout.write(JSON.stringify(out));

